 1→import * as React from "react"
 2→import { cn } from "@/lib/utils"
 3→import { Loader2 } from "lucide-react"
 4→
 5→export interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
 6→  variant?: "default" | "secondary" | "destructive" | "outline" | "ghost" | "link"
 7→  size?: "sm" | "md" | "lg" | "icon"
 8→  isLoading?: boolean
 9→}
10→
11→const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
12→  ({ className, variant = "default", size = "md", isLoading, children, disabled, ...props }, ref) => {
13→    const variants: Record<string, string> = {
14→      default: "bg-primary text-primary-foreground hover:bg-primary/90",
15→      secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
16→      destructive: "bg-red-600 text-white hover:bg-red-700",
17→      outline: "border border-white/10 bg-transparent hover:bg-white/5 text-white",
18→      ghost: "hover:bg-white/5 text-white",
19→      link: "text-primary underline-offset-4 hover:underline p-0 h-auto",
20→    }
21→
22→    const sizes: Record<string, string> = {
23→      sm: "h-8 px-3 text-xs rounded-lg",
24→      md: "h-10 px-4 text-sm rounded-xl",
25→      lg: "h-12 px-6 text-base rounded-xl",
26→      icon: "h-10 w-10 rounded-xl",
27→    }
28→
29→    return (
30→      <button
31→        className={cn(
32→          "inline-flex items-center justify-center gap-2 font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 disabled:pointer-events-none disabled:opacity-50",
33→          variants[variant],
34→          sizes[size],
35→          className
36→        )}
37→        ref={ref}
38→        disabled={disabled || isLoading}
39→        {...props}
40→      >
41→        {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
42→        {children}
43→      </button>
44→    )
45→  }
46→)
47→Button.displayName = "Button"
48→
49→export { Button }
