 1→import * as React from "react"
 2→import { cn } from "@/lib/utils"
 3→
 4→interface AvatarProps extends React.HTMLAttributes<HTMLDivElement> {
 5→  src?: string | null
 6→  alt?: string
 7→  fallback: string
 8→  size?: "sm" | "md" | "lg"
 9→}
10→
11→function Avatar({ src, alt, fallback, size = "md", className, ...props }: AvatarProps) {
12→  const sizes: Record<string, string> = {
13→    sm: "h-8 w-8 text-xs",
14→    md: "h-10 w-10 text-sm",
15→    lg: "h-14 w-14 text-lg",
16→  }
17→
18→  const initials = fallback
19→    .split(" ")
20→    .map((n) => n[0])
21→    .join("")
22→    .toUpperCase()
23→    .slice(0, 2)
24→
25→  if (src) {
26→    return (
27→      <img
28→        src={src}
29→        alt={alt || fallback}
30→        className={cn("rounded-full object-cover", sizes[size], className)}
31→      />
32→    )
33→  }
34→
35→  return (
36→    <div
37→      className={cn(
38→        "inline-flex items-center justify-center rounded-full bg-primary/20 text-primary font-medium",
39→        sizes[size],
40→        className
41→      )}
42→      {...props}
43→    >
44→      {initials}
45→    </div>
46→  )
47→}
