 1→"use client"
 2→
 3→import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts"
 4→
 5→interface DataPoint {
 6→  date: string
 7→  score: number
 8→  citations: number
 9→  mentions: number
10→}
11→
12→interface VisibilityTrendChartProps {
13→  data: DataPoint[]
14→  metric?: "score" | "citations" | "mentions"
15→}
16→
17→const METRIC_CONFIG = {
18→  score: { color: "#10b981", label: "Score AEO" },
19→  citations: { color: "#3b82f6", label: "Citations" },
20→  mentions: { color: "#f59e0b", label: "Mentions" },
21→}
22→
23→export function VisibilityTrendChart({ data, metric = "score" }: VisibilityTrendChartProps) {
24→  const config = METRIC_CONFIG[metric]
25→
26→  return (
27→    <ResponsiveContainer width="100%" height={300}>
28→      <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
29→        <defs>
30→          <linearGradient id={`gradient-${metric}`} x1="0" y1="0" x2="0" y2="1">
31→            <stop offset="5%" stopColor={config.color} stopOpacity={0.3} />
32→            <stop offset="95%" stopColor={config.color} stopOpacity={0} />
33→          </linearGradient>
34→        </defs>
35→        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
36→        <XAxis
37→          dataKey="date"
38→          stroke="rgba(255,255,255,0.2)"
39→          tick={{ fill: "rgba(255,255,255,0.4)", fontSize: 12 }}
40→          axisLine={false}
41→          tickLine={false}
42→        />
43→        <YAxis
44→          stroke="rgba(255,255,255,0.2)"
45→          tick={{ fill: "rgba(255,255,255,0.4)", fontSize: 12 }}
46→          axisLine={false}
47→          tickLine={false}
48→          domain={metric === "score" ? [0, 100] : ["auto", "auto"]}
49→        />
50→        <Tooltip
51→          contentStyle={{
52→            backgroundColor: "#1a1d21",
53→            border: "1px solid rgba(255,255,255,0.1)",
54→            borderRadius: "12px",
55→            color: "#fff",
56→          }}
57→          labelStyle={{ color: "rgba(255,255,255,0.5)" }}
58→        />
59→        <Area
60→          type="monotone"
61→          dataKey={metric}
62→          stroke={config.color}
63→          strokeWidth={2}
64→          fill={`url(#gradient-${metric})`}
65→          dot={false}
66→          activeDot={{ r: 5, fill: config.color, stroke: "#0a0a0f", strokeWidth: 2 }}
67→        />
68→      </AreaChart>
69→    </ResponsiveContainer>
70→  )
71→}
