 1→import { createServerClient, type CookieOptions } from '@supabase/ssr'
 2→import { cookies } from 'next/headers'
 3→
 4→const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://placeholder.supabase.co'
 5→const SUPABASE_KEY = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || 'placeholder'
 6→
 7→export function createClient() {
 8→  const cookieStore = cookies()
 9→
10→  return createServerClient(
11→    SUPABASE_URL,
12→    SUPABASE_KEY,
13→    {
14→      cookies: {
15→        get(name: string) {
16→          return cookieStore.get(name)?.value
17→        },
18→        set(name: string, value: string, options: CookieOptions) {
19→          try {
20→            cookieStore.set({ name, value, ...options })
21→          } catch (error) {
22→            // The `set` method was called from a Server Component.
23→            // This can be ignored if you have middleware refreshing
24→            // user sessions.
25→          }
26→        },
27→        remove(name: string, options: CookieOptions) {
28→          try {
29→            cookieStore.set({ name, value: '', ...options })
30→          } catch (error) {
31→            // The `delete` method was called from a Server Component.
32→          }
33→        },
34→      },
35→    }
36→  )
37→}

 1→import Stripe from 'stripe';
 2→
 3→// Lazy initialization to avoid build-time env var errors
 4→let _stripe: Stripe | null = null;
 5→export const getStripe = () => {
 6→  if (!_stripe) {
 7→    _stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
 8→      apiVersion: '2024-04-10',
 9→      typescript: true,
10→    });
11→  }
12→  return _stripe;
13→};
14→
15→// Keep backward-compatible export (getter pattern)
16→export const stripe = new Proxy({} as Stripe, {
17→  get(_, prop) {
18→    return (getStripe() as any)[prop];
19→  },
20→});
