 1→/**
 2→ * Input sanitization utilities for API routes
 3→ */
 4→
 5→/**
 6→ * Strip HTML tags from a string to prevent XSS
 7→ */
 8→export function stripHtml(input: string): string {
 9→  return input.replace(/<[^>]*>/g, "")
10→}
11→
12→/**
13→ * Sanitize a string: trim, strip HTML, enforce max length
14→ */
15→export function sanitizeString(input: unknown, maxLength = 10_000): string {
16→  if (typeof input !== "string") return ""
17→  return stripHtml(input).trim().slice(0, maxLength)
18→}
19→
20→/**
21→ * Sanitize an object's string values recursively
22→ */
23→export function sanitizeInput<T extends Record<string, unknown>>(
24→  obj: T,
25→  maxStringLength = 10_000
26→): T {
27→  const result: Record<string, unknown> = {}
28→  for (const [key, value] of Object.entries(obj)) {
29→    if (typeof value === "string") {
30→      result[key] = sanitizeString(value, maxStringLength)
31→    } else if (typeof value === "number" || typeof value === "boolean") {
32→      result[key] = value
33→    } else if (Array.isArray(value)) {
34→      result[key] = value.map((item) =>
35→        typeof item === "string"
36→          ? sanitizeString(item, maxStringLength)
37→          : item
38→      )
39→    } else if (value !== null && typeof value === "object") {
40→      result[key] = sanitizeInput(value as Record<string, unknown>, maxStringLength)
41→    } else {
42→      result[key] = value
43→    }
44→  }
45→  return result as T
46→}
47→
48→/**
49→ * Validate that a UUID string is properly formatted
50→ */
51→export function isValidUUID(str: string): boolean {
52→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(str)
53→}
