  1→import { NextRequest, NextResponse } from "next/server"
  2→import { createClient } from "@/lib/supabase/server"
  3→import crypto from "crypto"
  4→import { checkRateLimit, rateLimitHeaders, API_KEY_DEFAULT_LIMIT } from "@/lib/rate-limit"
  5→
  6→interface ApiKeyContext {
  7→  workspaceId: string
  8→  scopes: string[]
  9→  keyId: string
 10→  rateLimit: number
 11→}
 12→
 13→/**
 14→ * Authenticate a v1 API request using an API key.
 15→ * Expects: Authorization: Bearer cb_xxxxx
 16→ */
 17→export async function authenticateApiKey(req: NextRequest): Promise<
 18→  | { success: true; context: ApiKeyContext }
 19→  | { success: false; response: NextResponse }
 20→> {
 21→  const authHeader = req.headers.get("authorization")
 22→  if (!authHeader?.startsWith("Bearer ")) {
 23→    return {
 24→      success: false,
 25→      response: NextResponse.json(
 26→        { error: "Missing or invalid Authorization header. Use: Bearer <api_key>" },
 27→        { status: 401 }
 28→      ),
 29→    }
 30→  }
 31→
 32→  const apiKey = authHeader.slice(7)
 33→  if (!apiKey.startsWith("cb_")) {
 34→    return {
 35→      success: false,
 36→      response: NextResponse.json(
 37→        { error: "Invalid API key format. Keys start with 'cb_'" },
 38→        { status: 401 }
 39→      ),
 40→    }
 41→  }
 42→
 43→  const keyHash = crypto.createHash("sha256").update(apiKey).digest("hex")
 44→
 45→  const supabase = createClient()
 46→  const { data, error } = await supabase
 47→    .from("api_keys")
 48→    .select("id, workspace_id, scopes, rate_limit, is_active, expires_at")
 49→    .eq("key_hash", keyHash)
 50→    .single()
 51→
 52→  if (error || !data) {
 53→    return {
 54→      success: false,
 55→      response: NextResponse.json({ error: "Invalid API key" }, { status: 401 }),
 56→    }
 57→  }
 58→
 59→  if (!data.is_active) {
 60→    return {
 61→      success: false,
 62→      response: NextResponse.json({ error: "API key is disabled" }, { status: 403 }),
 63→    }
 64→  }
 65→
 66→  if (data.expires_at && new Date(data.expires_at) < new Date()) {
 67→    return {
 68→      success: false,
 69→      response: NextResponse.json({ error: "API key has expired" }, { status: 403 }),
 70→    }
 71→  }
 72→
 73→  // Rate limit check
 74→  const limit = data.rate_limit || API_KEY_DEFAULT_LIMIT
 75→  const rl = checkRateLimit(`api:${data.id}`, limit)
 76→  if (!rl.success) {
 77→    return {
 78→      success: false,
 79→      response: NextResponse.json(
 80→        { error: "Rate limit exceeded. Try again later.", code: "RATE_LIMIT_EXCEEDED" },
 81→        { status: 429, headers: rateLimitHeaders(rl) }
 82→      ),
 83→    }
 84→  }
 85→
 86→  // Update last used
 87→  await supabase
 88→    .from("api_keys")
 89→    .update({ last_used_at: new Date().toISOString() })
 90→    .eq("id", data.id)
 91→
 92→  return {
 93→    success: true,
 94→    context: {
 95→      workspaceId: data.workspace_id,
 96→      scopes: data.scopes || ["read"],
 97→      keyId: data.id,
 98→      rateLimit: limit,
 99→    },
100→  }
101→}
102→
103→/**
104→ * Generate a new API key
105→ * Returns the raw key (only shown once) and the hash for storage
106→ */
107→export function generateApiKey(): { key: string; hash: string; prefix: string } {
108→  const randomBytes = crypto.randomBytes(32).toString("hex")
109→  const key = `cb_${randomBytes}`
110→  const hash = crypto.createHash("sha256").update(key).digest("hex")
111→  const prefix = `cb_${randomBytes.slice(0, 8)}...`
112→
113→  return { key, hash, prefix }
114→}
